    if (tileOut > static_cast<uint32_t>(totalOut)) tileOut = static_cast<uint32_t>(totalOut);
    uint32_t blockDim = (static_cast<uint32_t>(totalOut) + tileOut - 1) / tileOut;
    if (blockDim > MAX_BLOCK) blockDim = MAX_BLOCK;
