#include "kernel_operator.h"

class KernelCa6k00246Custom {
public:
    __aicore__ inline KernelCa6k00246Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t batchSize, uint32_t outChannels,
                                uint32_t inHeight, uint32_t inWidth,
                                uint32_t upscaleFactor, uint32_t inChannels,
                                uint32_t outHeight, uint32_t outWidth,
                                uint32_t outputSize, uint32_t tileSize,
                                uint32_t inputSize)
    {
        N_ = batchSize;
        C_ = outChannels;
        H_ = inHeight;
        W_ = inWidth;
        r_ = upscaleFactor;
        inC_ = inChannels;
        Hr_ = outHeight;
        Wr_ = outWidth;
        totalOut_ = outputSize;
        tileOut_ = tileSize;
        inputSize_ = inputSize;

        xGm_.SetGlobalBuffer((__gm__ float*)x, inputSize_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalOut_);
    }

    __aicore__ inline void Process()
    {
        if (totalOut_ == 0 || tileOut_ == 0) return;

        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t blockNum = AscendC::GetBlockNum();

        uint32_t start = blockIdx * tileOut_;
        uint32_t end = start + tileOut_;
        if (end > totalOut_) end = totalOut_;

        uint32_t strideHrWr = Hr_ * Wr_;
        uint32_t strideCHrWr = C_ * strideHrWr;
        uint32_t strideHW = H_ * W_;
        uint32_t strideinCHW = inC_ * strideHW;

        for (uint32_t idx = start; idx < end; ++idx) {
            uint32_t tmp1 = idx;
            uint32_t n = tmp1 / strideCHrWr;
            tmp1 -= n * strideCHrWr;
            uint32_t c = tmp1 / strideHrWr;
            tmp1 -= c * strideHrWr;
            uint32_t h_out = tmp1 / Wr_;
            uint32_t w_out = tmp1 % Wr_;

            uint32_t h = h_out / r_;
            uint32_t ri = h_out % r_;
            uint32_t w = w_out / r_;
            uint32_t rj = w_out % r_;

            uint32_t srcIdx = n * strideinCHW
                            + (c * r_ * r_ + ri * r_ + rj) * strideHW
                            + h * W_
                            + w;

            float val = xGm_[srcIdx];
            yGm_[idx] = val;
        }
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_ {0};
    uint32_t C_ {0};
    uint32_t H_ {0};
    uint32_t W_ {0};
    uint32_t r_ {1};
    uint32_t inC_ {0};
    uint32_t Hr_ {0};
    uint32_t Wr_ {0};
    uint32_t totalOut_ {0};
    uint32_t tileOut_ {0};
    uint32_t inputSize_ {0};
};

